# tests/integration/test_document_agent.py
#
# Exercises the full agent loop: LLM call -> tool dispatch -> DB query -> answer.
# The database is seeded in conftest.py; the LLM is real but uses Haiku for cost.

import json
import pytest
import sqlite3
import anthropic
from typing import Any

pytest.mark.integration  # run with: pytest -m integration


class DocumentSearchAgent:
    """Minimal agentic loop: searches a SQLite database via LLM-driven tool use."""

    TOOLS = [
        {
            "name": "search_documents",
            "description": "Search the document database for entries matching a keyword.",
            "input_schema": {
                "type": "object",
                "properties": {
                    "keyword": {"type": "string", "description": "Keyword to search for"},
                },
                "required": ["keyword"],
            },
        }
    ]

    def __init__(self, client: anthropic.Anthropic, db_conn: sqlite3.Connection):
        self.client = client
        self.db_conn = db_conn
        self.call_log: list[dict[str, Any]] = []

    def _search_documents(self, keyword: str) -> list[dict]:
        """Real DB call — returns rows matching the keyword in title or body."""
        cursor = self.db_conn.execute(
            "SELECT id, title, body FROM documents "
            "WHERE title LIKE ? OR body LIKE ? LIMIT 5",
            (f"%{keyword}%", f"%{keyword}%"),
        )
        return [{"id": r[0], "title": r[1], "body": r[2]} for r in cursor.fetchall()]

    def run(self, question: str) -> str:
        messages = [{"role": "user", "content": question}]
        while True:
            response = self.client.messages.create(
                model="claude-3-haiku-20240307",
                max_tokens=512,
                tools=self.TOOLS,
                messages=messages,
            )
            messages.append({"role": "assistant", "content": response.content})

            if response.stop_reason == "end_turn":
                # Extract final text
                for block in response.content:
                    if hasattr(block, "text"):
                        return block.text
                return ""

            # Handle tool use
            tool_results = []
            for block in response.content:
                if block.type == "tool_use":
                    self.call_log.append({"tool": block.name, "input": block.input})
                    if block.name == "search_documents":
                        result = self._search_documents(block.input["keyword"])
                    else:
                        result = {"error": f"Unknown tool: {block.name}"}
                    tool_results.append({
                        "type": "tool_result",
                        "tool_use_id": block.id,
                        "content": json.dumps(result),
                    })

            messages.append({"role": "user", "content": tool_results})


@pytest.mark.integration
def test_agent_retrieves_document_from_database(llm_client, test_db):
    """Full integration: agent uses tool to query real DB and returns an answer."""
    _, db_conn = test_db
    agent = DocumentSearchAgent(client=llm_client, db_conn=db_conn)

    answer = agent.run("What does the database say about Python 3.13?")

    # Structural assertions — do not assert exact LLM phrasing
    assert isinstance(answer, str) and len(answer) > 20, (
        f"Expected a non-trivial answer, got: {answer!r}"
    )
    # Verify the agent actually invoked the tool (cross-boundary call happened)
    assert any(entry["tool"] == "search_documents" for entry in agent.call_log), (
        "Expected agent to call search_documents tool"
    )
    # Verify the answer references the seeded content (loose substring check)
    assert "3.13" in answer or "Python" in answer, (
        f"Answer should mention Python 3.13, got: {answer!r}"
    )
